import{_ as o,o as t,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"60. Family Violence Leave","description":"","frontmatter":{"title":"60. Family Violence Leave","eba":"Medical Specialists 2022-2026","topics":["leave","family-violence-leave","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/60-family-violence-leave.md","filePath":"ebas/medical-specialists/leave/60-family-violence-leave.md"}'),n={name:"ebas/medical-specialists/leave/60-family-violence-leave.md"};function r(s,e,l,c,p,m){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_60-family-violence-leave" tabindex="-1">60. Family Violence Leave <a class="header-anchor" href="#_60-family-violence-leave" aria-label="Permalink to &quot;60. Family Violence Leave&quot;">​</a></h1><p>NOTE: Family member is defined in section 8 of the Family Violence Protection Act 2008 (Vic) and is broader than the definition of immediate family in subclause 49.2.</p><p><strong>60.1</strong> General Principle</p><p><strong>(a)</strong> Each Health Service recognises that Doctors sometimes face situations of violence or abuse in their personal life that may affect their attendance or performance at work. Therefore, each Health Service is committed to providing support to staff that experience family violence.</p><p><strong>(b)</strong> Leave for family violence purposes is available to Doctors who are experiencing family violence and also to allow them to be absent from the workplace to attend counselling appointments, medical appointments, legal proceedings or appointments with a legal practitioner and other activities related to, and as a consequence of, family violence.</p><p><strong>60.2</strong> Definition of Family Violence</p><p>For the purposes of this clause, family violence is as defined by the Family Violence Protection Act 2008 (Vic) which defines family violence at section 5, in part, as follows:</p><p><strong>(a)</strong> behaviour by a person towards a family member of that person if that behaviour:</p><p><strong>(i)</strong> is physically or sexually abusive; or</p><p><strong>(ii)</strong> is emotionally or psychologically abusive; or</p><p><strong>(iii)</strong> is economically abusive; or</p><p><strong>(iv)</strong> is threatening; or</p><p><strong>(v)</strong> is coercive; or</p><p><strong>(vi)</strong> in any other way controls or dominates the family member and causes that family member to feel fear for the safety or wellbeing of that family member or another person; or</p><p><strong>(b)</strong> behaviour by a person that causes a child to hear or witness, or otherwise be exposed to the effects of, behaviour referred to in subclause (a) above.</p><p><strong>60.3</strong> Eligibility</p><p><strong>(a)</strong> Paid leave for family violence purposes is available to all Doctors with the exception of Internal Locum Doctors.</p><p><strong>(b)</strong> Internal Locum Doctors are entitled to access leave without pay for family violence purposes.</p><p><strong>60.4</strong> General Measures</p><p><strong>(a)</strong> Evidence of family violence may be required and can be in the form an agreed document issued by the Police Service, a Court, a registered health practitioner, a Family Violence Support Service, district nurse, maternal and child health nurse or Lawyer. A signed statutory declaration can also be offered as evidence.</p><p><strong>(b)</strong> All personal information concerning family violence will be kept confidential in line with the Health Service’s policies and relevant legislation. No information will be kept on a Doctor’s personnel file without their express written permission.</p><p><strong>(c)</strong> No adverse action will be taken against a Doctor if their attendance or performance at work suffers as a result of experiencing family violence.</p><p><strong>(d)</strong> The Health Service will identify contact/s within the workplace who will be trained in family violence and associated privacy issues. The Health Service will advertise the name of any Family Violence contacts within the workplace.</p><p><strong>(e)</strong> A Doctor experiencing family violence may raise the issue with their immediate supervisor, Family Violence contacts, Ambassador or nominated Human Resources contact. The immediate supervisor may seek advice from Human Resources if the Doctor chooses not to see the Human Resources or Family Violence contact.</p><p><strong>(f)</strong> Where requested by a Doctor, the Human Resources contact will liaise with the Doctor’s manager on the Doctor’s behalf, and will make a recommendation on the most appropriate form of support to provide in accordance with subclause 60.5 and subclause 60.6.</p><p><strong>(g)</strong> The Health Service will develop guidelines to supplement this clause and which details the appropriate action to be taken in the event that a Doctor reports family violence.</p><p><strong>60.5</strong> Leave</p><p><strong>(a)</strong> A Doctor experiencing family violence will have access to 20 days per year of paid special leave (pro rata for part time Doctors) following an event of family violence and for related purposes such as counselling appointments, medical appointments, legal proceedings or appointments with a legal practitioner and other activities related to, and as a consequence of, family violence (this leave is not cumulative but if the leave is exhausted consideration will be given to providing additional leave). This leave will be in addition to existing leave entitlements and may be taken as consecutive or single days or as a fraction of a day and can be taken without prior approval.</p><p><strong>(b)</strong> A Doctor who supports a person experiencing family violence may utilise their personal/carer&#39;s leave entitlement to accompany them to court, to hospital, or to care for children. The Health Service may require evidence consistent with subclause 60.4(a) from a Doctor seeking to utilise their personal/carer’s leave entitlement.</p><p><strong>60.6</strong> Individual Support</p><p><strong>(a)</strong> In order to provide support to a Doctor experiencing family violence and to provide a safe work environment to all Doctors, the Health Service will</p><p>approve any reasonable request from a Doctor experiencing family violence for:</p><p><strong>(i)</strong> temporary or ongoing changes to their span of hours or pattern or hours and/or shift patterns;</p><p><strong>(ii)</strong> temporary or ongoing job redesign or changes to duties;</p><p><strong>(iii)</strong> temporary or ongoing relocation to suitable employment;</p><p><strong>(iv)</strong> a change to their telephone number or email address to avoid harassing contact;</p><p><strong>(v)</strong> any other appropriate measure including those available under existing provisions for family friendly and flexible work arrangements.</p><p><strong>(b)</strong> Any changes to a Doctor’s role should be reviewed at agreed periods. When a Doctor is no longer experiencing family violence, the terms and conditions of employment may revert back to the terms and conditions applicable to the Doctor’s substantive position.</p><p><strong>(c)</strong> A Doctor experiencing family violence will be offered access to the Doctor Assistance Program (EAP) and/or other available local Doctor support resources. The EAP will include professionals trained specifically in family violence.</p><p><strong>(d)</strong> A Doctor that discloses that they are experiencing family violence will be given information regarding current support services.</p><p>Plain language terms: DV leave, domestic violence.</p>',41)])])}const g=o(n,[["render",r]]);export{d as __pageData,g as default};
